import { useMemo } from "react";
const defaultAggregations = {};
export function useAggregationFn(aggregate, fns = defaultAggregations) {
    return useMemo(() => {
        if (!aggregate)
            return null;
        if (!Array.isArray(aggregate))
            return aggregate;
        return (data) => {
            const result = {};
            for (const agg of aggregate) {
                const fn = typeof agg.fn === "string" ? fns[agg.fn] : agg.fn;
                if (!fn) {
                    console.error(`Unknown aggregation function applied: ${agg.fn}`);
                    continue;
                }
                result[agg.dim.id] = fn(agg.dim.field ?? agg.dim.id, data);
            }
            return result;
        };
    }, [aggregate, fns]);
}
